import { useState } from "react";
import { authClient } from "../../lib/auth-client";
import { Button } from "../ui/button";
import {
	Card,
	CardContent,
	CardDescription,
	CardHeader,
	CardTitle,
} from "../ui/card";
import { Input } from "../ui/input";
import { Label } from "../ui/label";
import { Separator } from "../ui/separator";

function getCallbackURL(): string {
	const params = new URLSearchParams(window.location.search);
	const cliCallback = params.get("cli_callback");
	const state = params.get("state");
	if (cliCallback && state) {
		return `/?cli_callback=${encodeURIComponent(cliCallback)}&state=${encodeURIComponent(state)}`;
	}
	const redirect = params.get("redirect");
	if (redirect) {
		return `/?redirect=${encodeURIComponent(redirect)}`;
	}
	const path = window.location.pathname;
	if (path !== "/" && path !== "") {
		return `/?redirect=${encodeURIComponent(path)}`;
	}
	return "/";
}

export function SignupForm({
	onSwitchToLogin,
}: {
	onSwitchToLogin: () => void;
}) {
	const [name, setName] = useState("");
	const [email, setEmail] = useState("");
	const [password, setPassword] = useState("");
	const [error, setError] = useState("");
	const [loading, setLoading] = useState(false);

	async function handleSubmit(e: React.FormEvent) {
		e.preventDefault();
		setError("");
		setLoading(true);
		const { error } = await authClient.signUp.email({
			name,
			email,
			password,
		});
		setLoading(false);
		if (error) {
			setError(error.message ?? "Sign up failed");
		}
	}

	async function handleSocialSignIn(provider: "google" | "github") {
		setError("");
		const { error } = await authClient.signIn.social({
			provider,
			callbackURL: getCallbackURL(),
		});
		if (error) {
			setError(error.message ?? `Sign up with ${provider} failed`);
		}
	}

	return (
		<Card className="w-full max-w-sm">
			<CardHeader>
				<CardTitle className="text-2xl">Create account</CardTitle>
				<CardDescription>
					Enter your details to create a new account
				</CardDescription>
			</CardHeader>
			<CardContent className="flex flex-col gap-4">
				<form onSubmit={handleSubmit} className="flex flex-col gap-4">
					<div className="flex flex-col gap-2">
						<Label htmlFor="name">Name</Label>
						<Input
							id="name"
							type="text"
							placeholder="Your name"
							value={name}
							onChange={(e) => setName(e.target.value)}
							required
						/>
					</div>
					<div className="flex flex-col gap-2">
						<Label htmlFor="email">Email</Label>
						<Input
							id="email"
							type="email"
							placeholder="you@example.com"
							value={email}
							onChange={(e) => setEmail(e.target.value)}
							required
						/>
					</div>
					<div className="flex flex-col gap-2">
						<Label htmlFor="password">Password</Label>
						<Input
							id="password"
							type="password"
							value={password}
							onChange={(e) => setPassword(e.target.value)}
							required
							minLength={8}
						/>
					</div>
					{error && <p className="text-sm text-destructive">{error}</p>}
					<Button type="submit" disabled={loading}>
						{loading ? "Creating account..." : "Sign up"}
					</Button>
				</form>

				<div className="flex items-center gap-2">
					<Separator className="flex-1" />
					<span className="text-xs text-muted-foreground">OR</span>
					<Separator className="flex-1" />
				</div>

				<div className="flex flex-col gap-2">
					<Button
						variant="outline"
						onClick={() => handleSocialSignIn("google")}
					>
						Continue with Google
					</Button>
					<Button
						variant="outline"
						onClick={() => handleSocialSignIn("github")}
					>
						Continue with GitHub
					</Button>
				</div>

				<p className="text-center text-sm text-muted-foreground">
					Already have an account?{" "}
					<button
						type="button"
						onClick={onSwitchToLogin}
						className="underline underline-offset-4 hover:text-primary"
					>
						Sign in
					</button>
				</p>
			</CardContent>
		</Card>
	);
}

